using System;
using System.Collections.Generic;
using UnityEngine;

namespace GenerationLogic
{
    public static class TreeGenerator
    {
        // generateTrees: given `heights` and `values` (0..1), where the lists
        // form a square grid (side = sqrt(length)), produce a list of 3D points
        // whose x/z correspond to grid positions and y is taken from `heights`.
        // Poisson-like sampling is approximated by shuffling cells and enforcing
        // a minimum distance that is scaled per-cell by `values` (higher value -> denser).
        public static List<Vector3> generateTrees(List<float> heights, List<float> values, float minRadius = 0.7f, float maxRadius = 2.0f, float jitter = 0.3f)
        {
            if (heights == null) throw new ArgumentNullException(nameof(heights));
            if (values == null) throw new ArgumentNullException(nameof(values));
            if (heights.Count != values.Count) throw new ArgumentException("heights and values must have the same length");

            int n = heights.Count;
            int side = Mathf.RoundToInt(Mathf.Sqrt(n));
            if (side * side != n) throw new ArgumentException("lists length must be a perfect square (side*side)");

            List<Vector3> result = new List<Vector3>();

            // shuffle indices to randomize placement order (dart throwing over grid)
            int[] indices = new int[n];
            for (int i = 0; i < n; i++) indices[i] = i;
            System.Random rng = new System.Random();
            for (int i = n - 1; i > 0; i--)
            {
                int j = rng.Next(i + 1);
                int tmp = indices[i]; indices[i] = indices[j]; indices[j] = tmp;
            }

            // iterate cells in random order and accept if it respects min-distance
            foreach (int idx in indices)
            {
                int gx = idx % side;
                int gz = idx / side;

                float v = Mathf.Clamp01(values[idx]);
                // map value -> local radius: higher value -> smaller radius (denser)
                float localRadius = Mathf.Lerp(maxRadius, minRadius, v);

                // candidate position: center of cell plus small jitter
                float x = gx + 0.5f + ((float)rng.NextDouble() * 2f - 1f) * jitter;
                float z = gz + 0.5f + ((float)rng.NextDouble() * 2f - 1f) * jitter;

                bool ok = true;
                float rr = localRadius * localRadius;
                for (int k = 0; k < result.Count; k++)
                {
                    Vector3 p = result[k];
                    float dx = p.x - x;
                    float dz = p.z - z;
                    if (dx * dx + dz * dz < rr)
                    {
                        ok = false; break;
                    }
                }

                if (ok)
                {
                    float y = heights[idx];
                    result.Add(new Vector3(x, y, z));
                }
            }

            return result;
        }
    }
}

