Short answer: easiest is to raycast against a Collider (MeshCollider) and read `RaycastHit.point`. If you don't have a collider, do a per-triangle Ray→Triangle test (Möller–Trumbore). Two minimal examples:

1) Raycast using a Collider (recommended)
```
using UnityEngine;

public static bool RaycastAgainstCollider(Vector3 origin, Vector3 direction, out Vector3 hitPoint, float maxDistance = Mathf.Infinity)
{
    Ray ray = new Ray(origin, direction.normalized);
    RaycastHit hit;
    if (Physics.Raycast(ray, out hit, maxDistance))
    {
        hitPoint = hit.point;
        return true;
    }
    hitPoint = Vector3.zero;
    return false;
}

// OR raycast a specific collider (e.g. MeshCollider on an object)
public static bool RaycastCollider(Collider col, Vector3 origin, Vector3 direction, out Vector3 hitPoint, float maxDistance = Mathf.Infinity)
{
    Ray ray = new Ray(origin, direction.normalized);
    RaycastHit hit;
    if (col.Raycast(ray, out hit, maxDistance))
    {
        hitPoint = hit.point;
        return true;
    }
    hitPoint = Vector3.zero;
    return false;
}
```
Notes: ensure the target GameObject has an enabled `MeshCollider` (or other collider). `Physics.Raycast` will return `hit.point` and `hit.normal`.

2) Raycast against a `Mesh` without a collider (Möller–Trumbore)
```
using UnityEngine;

public static bool RaycastMesh(Mesh mesh, Transform meshTransform, Ray ray, out Vector3 hitPoint, out Vector3 hitNormal)
{
    hitPoint = Vector3.zero;
    hitNormal = Vector3.zero;
    var verts = mesh.vertices;
    var tris = mesh.triangles;
    float bestT = float.MaxValue;
    bool hit = false;

    for (int i = 0; i < tris.Length; i += 3)
    {
        Vector3 v0 = meshTransform.TransformPoint(verts[tris[i]]);
        Vector3 v1 = meshTransform.TransformPoint(verts[tris[i + 1]]);
        Vector3 v2 = meshTransform.TransformPoint(verts[tris[i + 2]]);

        if (RayTriangleIntersect(ray.origin, ray.direction, v0, v1, v2, out float t, out float u, out float v))
        {
            if (t > 0f && t < bestT)
            {
                bestT = t;
                hit = true;
                hitPoint = ray.origin + ray.direction * t;
                hitNormal = Vector3.Cross(v1 - v0, v2 - v0).normalized;
            }
        }
    }
    return hit;
}

// Möller–Trumbore
static bool RayTriangleIntersect(Vector3 orig, Vector3 dir, Vector3 v0, Vector3 v1, Vector3 v2,
    out float t, out float u, out float v)
{
    t = u = v = 0f;
    const float EPSILON = 1e-6f;
    Vector3 edge1 = v1 - v0;
    Vector3 edge2 = v2 - v0;
    Vector3 pvec = Vector3.Cross(dir, edge2);
    float det = Vector3.Dot(edge1, pvec);
    if (det > -EPSILON && det < EPSILON) return false;
    float invDet = 1f / det;
    Vector3 tvec = orig - v0;
    u = Vector3.Dot(tvec, pvec) * invDet;
    if (u < 0f || u > 1f) return false;
    Vector3 qvec = Vector3.Cross(tvec, edge1);
    v = Vector3.Dot(dir, qvec) * invDet;
    if (v < 0f || u + v > 1f) return false;
    t = Vector3.Dot(edge2, qvec) * invDet;
    return t > EPSILON;
}
```
Notes:
- Iterating every triangle is slower; use this only for occasional queries or small meshes (or accelerate with spatial partitioning / BVH).
- Transform vertices to world space (`TransformPoint`) before intersection.
- You can add backface-culling by checking `det` sign and/or skipping intersections where normal faces away.

